from lxml import etree

def process_soap_request(xml_data, dtd_file):
    # Load the DTD file for validation
    dtd = etree.DTD(dtd_file)
    
    # Parse the incoming SOAP XML data with DTD validation
    try:
        root = etree.fromstring(xml_data, parser=etree.XMLParser(dtd_validation=True))
        if not dtd.validate(root):
            raise ValueError("DTD validation failed")
    except etree.XMLSyntaxError as e:
        raise ValueError(f"XML syntax error: {e}")
    
    # Extract the SOAP body
    soap_body = root.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
    if soap_body is None:
        raise ValueError("SOAP Body not found")
    
    return etree.tostring(soap_body, pretty_print=True).decode()